#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    double sum = 1.0; // Start with the first term 1

    for (int i = 2; i <= n; i++) {
        int numerator = 2 * i + 1;
        int denominator = i * i - 1;
        double term = ((i % 2 == 0) ? -1 : 1) * (double)numerator / denominator;
        sum += term;
    }

    printf("%.3f\n", sum);

    return 0;
}

