#include <stdio.h>
#include <math.h>

// Function to calculate the distance between two points
double distance(double x1, double y1, double x2, double y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

// Function to check if three points are collinear
int are_collinear(double x1, double y1, double x2, double y2, double x3, double y3) {
    return (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) == 0;
}

// Function to calculate the area of a triangle using Heron's formula
double herons_formula(double a, double b, double c) {
    double s = (a + b + c) / 2.0;
    return sqrt(s * (s - a) * (s - b) * (s - c));
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main(void) {
    int numbers[5], position, score = 0;
    char guess;
    srand(time(NULL));

    for (int i = 0; i < 5; i++) numbers[i] = rand() % 10 + 1;

    printf("Numbers: ");
    for (int i = 0; i < 5; i++) {
        printf("%d ", numbers[i]);
    }
    printf("\nPick ");

    if (scanf("%d %c", &position, &guess) == 2) {
        if (position >= 1 && position <= 5) {
            int number = numbers[position - 1];
            char correct_guess = (number % 2 == 0) ? 'E' : 'O';
            if (guess == correct_guess) {
                score += 5;
            }
        }
    }

    printf("win %d points\n", score);
    return 0;
}
